class Solution:
    def generateParenthesis(self, n: int) -> List[str]:
        res = []
        def bt(s, o, c):
            if len(s) == 2 * n:
                res.append(''.join(s)); return
            if o < n:
                s.append('('); bt(s, o + 1, c); s.pop()
            if c < o:
                s.append(')'); bt(s, o, c + 1); s.pop()
        bt([], 0, 0)
        return res

