class Solution {
    vector<string> res;
    void bt(string cur, int o, int c, int n) {
        if ((int)cur.size() == 2 * n) { res.push_back(cur); return; }
        if (o < n) bt(cur + '(', o + 1, c, n);
        if (c < o) bt(cur + ')', o, c + 1, n);
    }
public:
    vector<string> generateParenthesis(int n) {
        bt("", 0, 0, n); return res;
    }
};

