static void gp22(char** res, int* cnt, char* cur, int pos, int o, int c, int n) {
    if (pos == 2 * n) { res[(*cnt)++] = strdup(cur); return; }
    if (o < n) { cur[pos] = '('; cur[pos + 1] = 0; gp22(res, cnt, cur, pos + 1, o + 1, c, n); }
    if (c < o) { cur[pos] = ')'; cur[pos + 1] = 0; gp22(res, cnt, cur, pos + 1, o, c + 1, n); }
}
char** generateParenthesis(int n, int* returnSize) {
    char** res = (char**)malloc(5000 * sizeof(char*));
    char* cur = (char*)calloc(2 * n + 1, 1);
    *returnSize = 0;
    gp22(res, returnSize, cur, 0, 0, 0, n);
    free(cur);
    return res;
}
